function pickUiPreference<T>(
  source: Record<string, unknown>,
  key: keyof UiPreferencesInput,
  fallback: T,
  isValid: (value: unknown) => value is T
): T {
  const value = source[key];
  return isValid(value) ? value : fallback;
}

